mapper.sql:
where o.tenant_id = #{tenantId}

    and (lower(o.object_code) like concat('%', lower(#{keyword}), '%')
      or lower(o.object_name) like concat('%', lower(#{keyword}), '%')
      or lower(o.match_pattern) like concat('%', lower(#{keyword}), '%'))

and o.env_id = #{envId}
and o.region_id = #{regionId}
and o.object_type = #{objectType}
and o.source_type = #{sourceType}
and o.enabled = #{enabled}
